#! /usr/bin/perl

use Getopt::Long;

my $cutoff=5;
GetOptions ('cutoff=s' => \$cutoff );

%calltree = ();
%allfun = ();

while (<>) {
   if (/^sample\.interval=/) {
   	s/sample\.interval=//;
   	$sample = $_ / 1e6;
   } else {
	  chomp;
	  @line = reverse split(/ /);

     $caller = shift(@line);
     $allfun{$caller}++;
     while( $called = shift(@line) ){
       $allfun{$called}++;
       $calltree{$caller}{$called} ++ ;
       $caller = $called;
     }

   }
}

print "digraph {\n" ;
print 'graph [ rankdir = "LR"]; '."\n";
foreach $fun (keys %allfun){
